import java.util.Arrays;

public static long solve(long[] nums, long k) {
    Arrays.sort(nums);
    int n = nums.length;
    int minRemove = n - 1; // Initialize with the worst case

    for (int i = 0; i < n; ++i) {
        long minVal = nums[i];
        long maxAllowed = minVal * k;
        int j = Arrays.binarySearch(nums, maxAllowed);
        if (j < 0) {
            j = -j - 1;
        } else {
            j = j + 1;
        }
        while (j < n && nums[j] <= maxAllowed) {
            j++;
        }
        minRemove = Math.min(minRemove, n - (j - i));
    }

    return minRemove;
}
