        minRemove = Math.min(minRemove, n - (j - i));
    }

    return minRemove;
}

private static int upperBound(long[] nums, long target) {
    int left = 0, right = nums.length;
    while (left < right) {
        int mid = left + (right - left) / 2;
        if (nums[mid] <= target) {
            left = mid + 1;
        } else {
            right = mid;
        }
    }
    return left;
}
